-- ----------------------------------------------------------------------------
-- Capabilities: Cognitive capabilities being assessed. Tiered foundational/composite/emergent and weighted by importance.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS capabilities (
  capabilities_id                     TEXT                 PRIMARY KEY          -- Slug for the capability (e.g. 'reasoning'). First raw field is the PK.
);
ALTER TABLE capabilities ADD COLUMN IF NOT EXISTS description TEXT;                                 -- Short prose describing the capability.
ALTER TABLE capabilities ADD COLUMN IF NOT EXISTS tier TEXT;                                        -- Capability tier: foundational, composite, or emergent.
ALTER TABLE capabilities ADD COLUMN IF NOT EXISTS weight NUMERIC;                                   -- Importance multiplier used when computing WeightedScore on each Assessment.
COMMENT ON TABLE capabilities IS 'Cognitive capabilities being assessed. Tiered foundational/composite/emergent and weighted by importance.';
COMMENT ON COLUMN capabilities.capabilities_id IS 'Slug for the capability (e.g. ''reasoning''). First raw field is the PK.';
COMMENT ON COLUMN capabilities.description IS 'Short prose describing the capability.';
COMMENT ON COLUMN capabilities.tier IS 'Capability tier: foundational, composite, or emergent.';
COMMENT ON COLUMN capabilities.weight IS 'Importance multiplier used when computing WeightedScore on each Assessment.';

-- ----------------------------------------------------------------------------
-- Intelligences: Agents being classified by the taxonomy. Each Intelligence's TaxonomyClass is derived from the rollup of its Assessments.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS intelligences (
  intelligences_id                    TEXT                 PRIMARY KEY          -- Slug for the intelligence (e.g. 'human'). First raw field is the PK.
);
ALTER TABLE intelligences ADD COLUMN IF NOT EXISTS description TEXT;                                -- Short prose describing what this intelligence is.
ALTER TABLE intelligences ADD COLUMN IF NOT EXISTS substrate TEXT;                                  -- Substrate kind: biological, digital, or collective.
COMMENT ON TABLE intelligences IS 'Agents being classified by the taxonomy. Each Intelligence''s TaxonomyClass is derived from the rollup of its Assessments.';
COMMENT ON COLUMN intelligences.intelligences_id IS 'Slug for the intelligence (e.g. ''human''). First raw field is the PK.';
COMMENT ON COLUMN intelligences.description IS 'Short prose describing what this intelligence is.';
COMMENT ON COLUMN intelligences.substrate IS 'Substrate kind: biological, digital, or collective.';

-- ----------------------------------------------------------------------------
-- Assessments: Per-capability scores for each intelligence. The junction table whose calculated WeightedScore feeds the rollup on Intelligences.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS assessments (
  assessments_id                      TEXT                 PRIMARY KEY          -- Slug encoding the intelligence-capability pair (e.g. 'human-reasoning'). First raw field is the PK.
);
ALTER TABLE assessments ADD COLUMN IF NOT EXISTS intelligence TEXT;                                 -- FK to Intelligences. Holds the value of Intelligences.IntelligencesId.
ALTER TABLE assessments ADD COLUMN IF NOT EXISTS capability TEXT;                                   -- FK to Capabilities. Holds the value of Capabilities.CapabilitiesId.
ALTER TABLE assessments ADD COLUMN IF NOT EXISTS raw_score INTEGER;                                 -- User-editable assessment score from 0 to 100. Edit this in the UI to watch the cascade.
COMMENT ON TABLE assessments IS 'Per-capability scores for each intelligence. The junction table whose calculated WeightedScore feeds the rollup on Intelligences.';
COMMENT ON COLUMN assessments.assessments_id IS 'Slug encoding the intelligence-capability pair (e.g. ''human-reasoning''). First raw field is the PK.';
COMMENT ON COLUMN assessments.intelligence IS 'FK to Intelligences. Holds the value of Intelligences.IntelligencesId.';
COMMENT ON COLUMN assessments.capability IS 'FK to Capabilities. Holds the value of Capabilities.CapabilitiesId.';
COMMENT ON COLUMN assessments.raw_score IS 'User-editable assessment score from 0 to 100. Edit this in the UI to watch the cascade.';

